// GROWTH-4: OpenProject WP 종결 이벤트 검증 및 정보 추출
// OpenProject webhook payload: { action, work_package: {...} }
// action: 'work_package:updated', 'work_package:closed' 등

const raw = $json;
const body = raw.body || raw;

const action = body.action || '';
const wp = body.work_package || body.workPackage || null;

if (!wp) {
  throw new Error('No work_package in payload. action=' + action);
}

const wpId = wp.id;
if (!wpId) {
  throw new Error('work_package.id missing');
}

// 종결 상태 확인: status.title이 Closed/종결/완료 포함이거나 action이 closed
const statusTitle = ((wp.status || {}).title || '').toLowerCase();
const isClosed = statusTitle.includes('clos') || statusTitle.includes('종결') || statusTitle.includes('완료') || action.includes('clos');
if (!isClosed) {
  throw new Error('Not a close event. status=' + statusTitle + ' action=' + action);
}

// WP 기본 정보 추출
const subject = wp.subject || '';
const desc = typeof wp.description === 'object' ? (wp.description.raw || wp.description.html || '') : (wp.description || '');
const closedAt = wp.updatedAt || wp.closedAt || new Date().toISOString();
const createdAt = wp.createdAt || closedAt;

// 지역 추출 (backfill 로직과 동일)
let region = 'UNKNOWN';
const subjectUpper = subject.toUpperCase();
for (const r of ['US', 'EU', 'KR']) {
  if (subjectUpper.includes(r)) { region = r; break; }
}
const cfs = wp.customFields || {};
for (const [, v] of Object.entries(cfs)) {
  const raw2 = (typeof v === 'object' ? v.raw : String(v)) || '';
  if (['US', 'EU', 'KR'].includes(raw2)) { region = raw2; break; }
}

// 프로젝트명 추출
const project = (typeof wp._links === 'object') ? ((wp._links.project || {}).title || '') : '';

// Case digest 구성 (구조적 추출 — backfill format 호환)
// device: 제목 첫 부분에서 추출, intended_use: description 첫 문단
const subjectParts = subject.split(/[:\-–]/).map((s) => s.trim());
const device = subjectParts[0] || subject.slice(0, 80);
const descLines = desc.split('\n').filter((l) => l.trim().length > 0);
const intendedUse = descLines[0] ? descLines[0].slice(0, 200) : '';

// RA 경로 추출: 제목에서 510(k)/PMA/CE/MFDS 키워드 검색
let pathway = null;
const subjectLower = subject.toLowerCase();
const descLower = desc.toLowerCase();
const pathwayKeywords = ['510(k)', '510k', 'pma', 'de novo', 'ce marking', 'mfds', 'kfda', 'class ii', 'class iii', 'exempt'];
for (const kw of pathwayKeywords) {
  if (subjectLower.includes(kw) || descLower.includes(kw)) {
    pathway = kw.toUpperCase();
    break;
  }
}

// predicate 추출: 제목/설명에서 K-number, 기존 디바이스 참조
const predicateMatch = (subject + ' ' + desc).match(/K\d{6}|predicate[:\s]+([^\n,]+)|similar to[:\s]+([^\n,]+)/i);
const chosenPredicate = predicateMatch ? predicateMatch[0].slice(0, 100) : null;

// 결과: 종결 = 승인 완료로 간주 (OP에서 Closed = successful completion)
const outcome = 'closed';

const digest = {
  device,
  intended_use: intendedUse,
  chosen_predicate: chosenPredicate,
  pathway,
  outcome,
  region,
  what_worked: null,
  what_didnt: null,
  _source: 'wp_close_webhook',
  _extractedAt: new Date().toISOString()
};

return [{
  json: {
    wp_id: wpId,
    session_id: 'wp-' + wpId,
    subject,
    region,
    project,
    closed_at: closedAt,
    created_at: createdAt,
    status: statusTitle,
    digest
  }
}];
